#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    while (Q--) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int x, y;
            scanf("%d %d", &x, &y);
            A[x - 1] = y;
        } else {
            int l, r;
            scanf("%d %d", &l, &r);
            int count[N + 1] = {0};
            for (int i = l - 1; i < r; i++) {
                count[A[i]]++;
            }
            int maxCount = 0;
            for (int i = 0; i <= N; i++) {
                if (count[i] > maxCount) {
                    maxCount = count[i];
                }
            }
            if (maxCount > (r - l + 1) / 2) {
                printf("Yes\n");
            } else {
                printf("No\n");
            }
        }
    }
    return 0;
}

