import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        while (Q-- > 0) {
            int type = sc.nextInt();
            if (type == 1) {
                int x = sc.nextInt();
                int y = sc.nextInt();
                A[x - 1] = y;
            } else {
                int l = sc.nextInt();
                int r = sc.nextInt();
                int[] count = new int[N + 1];
                for (int i = l - 1; i < r; i++) {
                    count[A[i]]++;
                }
                int maxCount = 0;
                for (int i = 0; i <= N; i++) {
                    if (count[i] > maxCount) {
                        maxCount = count[i];
                    }
                }
                if (maxCount > (r - l + 1) / 2) {
                    System.out.println("Yes");
                } else {
                    System.out.println("No");
                }
            }
        }
    }
}

