code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const [N, Q] = readline().split(' ').map(Number);
const A = readline().split(' ').map(Number);
for (let i = 0; i < Q; i++) {
    const [type, ...args] = readline().split(' ').map(Number);
    if (type === 1) {
        const [x, y] = args;
        A[x - 1] = y;
    } else {
        const [l, r] = args;
        const count = new Array(N + 1).fill(0);
        for (let j = l - 1; j < r; j++) {
            count[A[j]]++;
        }
        const maxCount = Math.max(...count);
        if (maxCount > (r - l + 1) / 2) {
            console.log('Yes');
        } else {
            console.log('No');
        }
    }
}

